const PROVIDER_ICON_LOOKUP = new Map<string, ProviderIconData>();

for (const definition of PROVIDER_ICON_DEFINITIONS) {
  for (const alias of definition.aliases) {
    PROVIDER_ICON_LOOKUP.set(normalizeProviderKey(alias), definition);
  }
}

export function getProviderIconData(
  providerID?: string,
  providerName?: string
): ProviderIconData | null {
  const fallback = PROVIDER_ICON_LOOKUP.get(normalizeProviderKey("opencode"));
  const direct = resolveProviderIconData(providerID, providerName);

  return direct ?? fallback ?? null;
}

export function hasDedicatedProviderIconData(
  providerID?: string,
  providerName?: string
) {
  return resolveProviderIconData(providerID, providerName) !== null;
}

export { PROVIDER_ICON_DEFINITIONS };

function resolveProviderIconData(
  providerID?: string,
  providerName?: string
): ProviderIconData | null {
  const direct = providerID
    ? PROVIDER_ICON_LOOKUP.get(normalizeProviderKey(providerID))
    : undefined;

  if (direct) {
    return direct;
  }

  const byName = providerName
    ? PROVIDER_ICON_LOOKUP.get(normalizeProviderKey(providerName))
    : undefined;

  return byName ?? null;
}

function normalizeProviderKey(value: string) {
  return value
    .toLowerCase()
    .trim()
    .replace(/[./_]+/g, "-")
    .replace(/\s+/g, "-")
    .replace(/-+/g, "-");
}
